import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../../services/api';
// Sesuaikan path import CSS module Anda
import styles from './Login.module.css'; 

const Login = ({ onLoginSuccess }) => {
    const navigate = useNavigate();

    // 1. Deklarasi State
    const [formData, setFormData] = useState({ email: '', password: '' });
    const [error, setError] = useState('');
    const [loading, setLoading] = useState(false);

    // 2. Fungsi handleChange (Wajib ada agar tidak "not defined")
    const handleChange = (e) => {
        setFormData({ ...formData, [e.target.name]: e.target.value });
    };

    // 3. Fungsi handleLogin
    const handleLogin = async (e) => {
        e.preventDefault();
        setError('');
        setLoading(true);

        try {
            const res = await api.post('/auth/login', formData);
            if (res.data?.token) {
                localStorage.setItem('token', res.data.token);
                localStorage.setItem('user_name', res.data.user?.nama_lengkap || 'User');

                alert('Login Berhasil!');
                if (onLoginSuccess) onLoginSuccess();
                navigate('/');
            }
        } catch (err) {
            setError(err.response?.data?.message || 'Email atau password salah!');
        } finally {
            setLoading(false);
        }
    };

    const handleGuestAccess = () => {
        alert('Anda masuk sebagai Guest');
        navigate('/');
    };

    // 4. Render (JSX)
    return (
        <div className={styles.loginBox}>
            <h2 className={styles.title}>Masuk Akun</h2>
            <p className={styles.subtitle}>Selamat datang kembali!</p>

            {/* Menampilkan error jika ada */}
            {error && <div className={styles.errorAlert}>{error}</div>}

            <form onSubmit={handleLogin} className={styles.form}>
                <div className={styles.formGroup}>
                    <label className={styles.label}>Email</label>
                    <input 
                        type="email" name="email" value={formData.email} 
                        onChange={handleChange} className={styles.input} required 
                    />
                </div>
                <div className={styles.formGroup}>
                    <label className={styles.label}>Password</label>
                    <input 
                        type="password" name="password" value={formData.password} 
                        onChange={handleChange} className={styles.input} required 
                    />
                </div>

                <button type="submit" disabled={loading} className={styles.btn}>
                    {loading ? 'Memverifikasi...' : 'Masuk Akun'}
                </button>
            </form>

            <button type="button" onClick={handleGuestAccess} className={styles.btnGuest}>
                🔍 Jelajahi Sebagai Guest
            </button>

            <p style={{ textAlign: 'center', marginTop: '20px' }}>
                Belum punya akun?{' '}
                <span onClick={() => navigate('/register')} style={{ color: '#ea580c', cursor: 'pointer' }}>
                    Daftar Sekarang
                </span>
            </p>
        </div>
    );
};

export default Login;
